// Ghost Releaser - determines when to release ghosts from home

import { GhostMode, GhostName } from '../types'
import {
	GHOST_TIMEOUT_EARLY,
	GHOST_TIMEOUT_LATE,
	PERSONAL_DOT_LIMITS,
	GLOBAL_DOT_LIMITS,
} from '../constants'
import type { Ghost } from '../core/Ghost'

/**
 * Releaser mode
 */
enum ReleaserMode {
	PERSONAL = 0,
	GLOBAL = 1,
}

/**
 * Ghost Releaser manages:
 * - Personal dot counting mode (new level)
 * - Global dot counting mode (after death)
 * - Timeout-based release when pacman stops eating
 */
export class GhostReleaser {
	private mode: ReleaserMode = ReleaserMode.PERSONAL
	private framesSinceLastDot: number = 0
	private ghostCounts: Record<GhostName, number> = {
		[GhostName.BLINKY]: 0,
		[GhostName.PINKY]: 0,
		[GhostName.INKY]: 0,
		[GhostName.CLYDE]: 0,
	}
	private globalCount: number = 0
	private level: number = 1
	private ghosts: Ghost[] = []

	/**
	 * Set references to ghosts (in order: Blinky, Pinky, Inky, Clyde)
	 */
	setGhosts(ghosts: Ghost[]): void {
		this.ghosts = ghosts
	}

	/**
	 * Set current level
	 */
	setLevel(level: number): void {
		this.level = level
	}

	/**
	 * Get timeout limit based on level
	 */
	private getTimeoutLimit(): number {
		return this.level < 5 ? GHOST_TIMEOUT_EARLY : GHOST_TIMEOUT_LATE
	}

	/**
	 * Get personal dot limit for a ghost
	 */
	private getPersonalDotLimit(ghostIndex: GhostName): number {
		switch (ghostIndex) {
			case GhostName.PINKY:
				return PERSONAL_DOT_LIMITS.PINKY(this.level)
			case GhostName.INKY:
				return PERSONAL_DOT_LIMITS.INKY(this.level)
			case GhostName.CLYDE:
				return PERSONAL_DOT_LIMITS.CLYDE(this.level)
			default:
				return 0
		}
	}

	/**
	 * Reset for new level (personal mode)
	 */
	onNewLevel(): void {
		this.mode = ReleaserMode.PERSONAL
		this.framesSinceLastDot = 0
		this.ghostCounts = {
			[GhostName.BLINKY]: 0,
			[GhostName.PINKY]: 0,
			[GhostName.INKY]: 0,
			[GhostName.CLYDE]: 0,
		}
	}

	/**
	 * Reset for level restart after death (global mode)
	 */
	onRestartLevel(): void {
		this.mode = ReleaserMode.GLOBAL
		this.framesSinceLastDot = 0
		this.globalCount = 0
	}

	/**
	 * Called when pacman eats a dot
	 */
	onDotEat(): void {
		this.framesSinceLastDot = 0

		if (this.mode === ReleaserMode.GLOBAL) {
			this.globalCount++
		} else {
			// Increment counter for first ghost still in home
			for (let i = 1; i < 4; i++) {
				if (this.ghosts[i] && this.ghosts[i].mode === GhostMode.PACING_HOME) {
					this.ghostCounts[i as GhostName]++
					break
				}
			}
		}
	}

	/**
	 * Update releaser each frame
	 */
	update(): void {
		// Personal dot counter mode
		if (this.mode === ReleaserMode.PERSONAL) {
			for (let i = 1; i < 4; i++) {
				const ghost = this.ghosts[i]
				if (ghost && ghost.mode === GhostMode.PACING_HOME) {
					if (
						this.ghostCounts[i as GhostName] >=
						this.getPersonalDotLimit(i as GhostName)
					) {
						ghost.leaveHome()
						return
					}
					break // Only check first ghost in home
				}
			}
		}
		// Global dot counter mode
		else if (this.mode === ReleaserMode.GLOBAL) {
			// Pinky
			if (
				this.globalCount === GLOBAL_DOT_LIMITS.PINKY &&
				this.ghosts[GhostName.PINKY]?.mode === GhostMode.PACING_HOME
			) {
				this.ghosts[GhostName.PINKY].leaveHome()
				return
			}
			// Inky
			else if (
				this.globalCount === GLOBAL_DOT_LIMITS.INKY &&
				this.ghosts[GhostName.INKY]?.mode === GhostMode.PACING_HOME
			) {
				this.ghosts[GhostName.INKY].leaveHome()
				return
			}
			// Clyde
			else if (
				this.globalCount === GLOBAL_DOT_LIMITS.CLYDE &&
				this.ghosts[GhostName.CLYDE]?.mode === GhostMode.PACING_HOME
			) {
				// Switch back to personal mode after Clyde leaves
				this.globalCount = 0
				this.mode = ReleaserMode.PERSONAL
				this.ghosts[GhostName.CLYDE].leaveHome()
				return
			}
		}

		// Timeout-based release when pacman stops eating
		if (this.framesSinceLastDot > this.getTimeoutLimit()) {
			this.framesSinceLastDot = 0
			for (let i = 1; i < 4; i++) {
				const ghost = this.ghosts[i]
				if (ghost && ghost.mode === GhostMode.PACING_HOME) {
					ghost.leaveHome()
					break
				}
			}
		} else {
			this.framesSinceLastDot++
		}
	}
}
