import { useEffect, useState } from 'react'

interface ImageAssets {
	spritesheet: HTMLImageElement
}

export const useImageLoader = (
	_skin?: string
): [ImageAssets | null, boolean, string | null] => {
	const [images, setImages] = useState<ImageAssets | null>(null)
	const [loading, setLoading] = useState(true)
	const [error, setError] = useState<string | null>(null)

	useEffect(() => {
		const loadImage = (src: string): Promise<HTMLImageElement> => {
			return new Promise((resolve, reject) => {
				const img = new Image()
				img.onload = () => resolve(img)
				img.onerror = () => reject(new Error(`Failed to load image: ${src}`))
				img.src = src
			})
		}

		const loadAllImages = async () => {
			try {
				setLoading(true)
				setError(null)

				const basePath = `/games/space-snake/img/`
				const spritesheet = await loadImage(`${basePath}sprites.webp`)

				setImages({ spritesheet })
			} catch (err) {
				setError(err instanceof Error ? err.message : 'Failed to load images')
			} finally {
				setLoading(false)
			}
		}

		loadAllImages()
	}, [])

	return [images, loading, error]
}
