// Map class for Pac-Man maze

import {
	TILE_SIZE,
	MID_TILE,
	MAP_COLS,
	MAP_ROWS,
	PACMAN_MAP,
	TUNNEL_MARGIN_TILES,
} from '../constants'
import {
	Direction,
	TunnelInfo,
	PathPoint,
	Position,
	TilePosition,
} from '../types'
import {
	setDirFromEnum,
	rotateLeft,
	rotateRight,
	rotateAboutFace,
	getClockwiseAngleFromTop,
} from './Direction'

export class GameMap {
	numCols: number
	numRows: number
	numTiles: number
	widthPixels: number
	heightPixels: number

	tiles: string
	currentTiles: string[]

	// Ghost home location
	doorTile: TilePosition
	doorPixel: Position
	homeTopPixel: number
	homeBottomPixel: number

	// Pellet tracking
	numDots: number
	numEnergizers: number
	dotsEaten: number
	energizers: TilePosition[]

	// Tunnel info
	tunnelRows: Record<number, TunnelInfo>

	// Wall paths for rendering
	paths: PathPoint[][]

	// Map colors
	wallStrokeColor: string
	wallFillColor: string
	pelletColor: string

	constructor(
		numCols: number = MAP_COLS,
		numRows: number = MAP_ROWS,
		tiles: string = PACMAN_MAP
	) {
		this.numCols = numCols
		this.numRows = numRows
		this.numTiles = numCols * numRows
		this.widthPixels = numCols * TILE_SIZE
		this.heightPixels = numRows * TILE_SIZE

		this.tiles = tiles
		this.currentTiles = []

		// Ghost home location
		this.doorTile = { x: 13, y: 14 }
		this.doorPixel = {
			x: (this.doorTile.x + 1) * TILE_SIZE - 1,
			y: this.doorTile.y * TILE_SIZE + MID_TILE.y,
		}
		this.homeTopPixel = 17 * TILE_SIZE
		this.homeBottomPixel = 18 * TILE_SIZE

		this.numDots = 0
		this.numEnergizers = 0
		this.dotsEaten = 0
		this.energizers = []

		this.tunnelRows = {}
		this.paths = []

		// Default colors
		this.wallStrokeColor = '#2121ff'
		this.wallFillColor = '#000'
		this.pelletColor = '#ffb8ae'

		this.resetCurrent()
		this.parseDots()
		this.parseTunnels()
		this.parseWalls()
	}

	/**
	 * Reset current tiles to initial state
	 */
	resetCurrent(): void {
		this.currentTiles = this.tiles.split('')
		this.dotsEaten = 0
	}

	/**
	 * Convert position to index
	 */
	posToIndex(x: number, y: number): number | undefined {
		if (x >= 0 && x < this.numCols && y >= 0 && y < this.numRows) {
			return x + y * this.numCols
		}
		return undefined
	}

	/**
	 * Get tile character at given coordinate
	 * Extended to include offscreen tunnel space
	 */
	getTile(x: number, y: number): string | undefined {
		if (x >= 0 && x < this.numCols && y >= 0 && y < this.numRows) {
			const idx = this.posToIndex(x, y)
			return idx !== undefined ? this.currentTiles[idx] : undefined
		}
		if (
			(x < 0 || x >= this.numCols) &&
			(this.isTunnelTile(x, y - 1) || this.isTunnelTile(x, y + 1))
		) {
			return '|'
		}
		if (this.isTunnelTile(x, y)) {
			return ' '
		}
		return undefined
	}

	/**
	 * Check if character is a walkable floor tile
	 */
	isFloorTileChar(tile: string | undefined): boolean {
		return tile === ' ' || tile === '.' || tile === 'o'
	}

	/**
	 * Check if tile at coordinate is walkable
	 */
	isFloorTile(x: number, y: number): boolean {
		return this.isFloorTileChar(this.getTile(x, y))
	}

	/**
	 * Check if tile is inside a tunnel
	 */
	isTunnelTile(x: number, y: number): boolean {
		const tunnel = this.tunnelRows[y]
		return (
			tunnel !== undefined &&
			(x < tunnel.leftEntrance || x > tunnel.rightEntrance)
		)
	}

	/**
	 * Count pellets and store energizer locations
	 */
	parseDots(): void {
		this.numDots = 0
		this.numEnergizers = 0
		this.energizers = []

		let i = 0
		for (let y = 0; y < this.numRows; y++) {
			for (let x = 0; x < this.numCols; x++) {
				const tile = this.tiles[i]
				if (tile === '.') {
					this.numDots++
				} else if (tile === 'o') {
					this.numDots++
					this.numEnergizers++
					this.energizers.push({ x, y })
				}
				i++
			}
		}
	}

	/**
	 * Get remaining dots
	 */
	dotsLeft(): number {
		return this.numDots - this.dotsEaten
	}

	/**
	 * Check if all dots eaten
	 */
	allDotsEaten(): boolean {
		return this.dotsLeft() === 0
	}

	/**
	 * Parse tunnel locations
	 */
	parseTunnels(): void {
		this.tunnelRows = {}

		const getTunnelEntrance = (x: number, y: number, dx: number): number => {
			while (
				!this.isFloorTile(x, y - 1) &&
				!this.isFloorTile(x, y + 1) &&
				this.isFloorTile(x, y)
			) {
				x += dx
			}
			return x
		}

		for (let y = 0; y < this.numRows; y++) {
			// A row is a tunnel if opposite ends are both walkable
			if (this.isFloorTile(0, y) && this.isFloorTile(this.numCols - 1, y)) {
				this.tunnelRows[y] = {
					leftEntrance: getTunnelEntrance(0, y, 1),
					rightEntrance: getTunnelEntrance(this.numCols - 1, y, -1),
					leftExit: -TUNNEL_MARGIN_TILES * TILE_SIZE,
					rightExit: (this.numCols + TUNNEL_MARGIN_TILES) * TILE_SIZE - 1,
				}
			}
		}
	}

	/**
	 * Teleport actor to other side of tunnel if necessary
	 */
	teleport(actor: { pixel: Position; tile: TilePosition }): void {
		const t = this.tunnelRows[actor.tile.y]
		if (t) {
			if (actor.pixel.x < t.leftExit) {
				actor.pixel.x = t.rightExit
			} else if (actor.pixel.x > t.rightExit) {
				actor.pixel.x = t.leftExit
			}
		}
	}

	/**
	 * Mark dot at coordinate as eaten
	 */
	onDotEat(x: number, y: number): void {
		this.dotsEaten++
		const i = this.posToIndex(x, y)
		if (i !== undefined) {
			this.currentTiles[i] = ' '
		}
	}

	/**
	 * Constrain ghost turns at specific tiles (Pac-Man specific)
	 * Prevents ghosts from turning up at certain intersections
	 */
	constrainGhostTurns(
		tile: TilePosition,
		openTiles: Record<Direction, boolean>
	): void {
		// Prevent ghost from turning up at these tiles
		if ((tile.x === 12 || tile.x === 15) && (tile.y === 14 || tile.y === 26)) {
			openTiles[Direction.UP] = false
		}
	}

	/**
	 * Parse wall structure for rendering
	 * Creates canvas paths for drawing maze walls
	 */
	parseWalls(): void {
		this.paths = []

		const visited: Record<number, boolean> = {}
		const edges: Record<number, boolean> = {}

		const toIndex = (x: number, y: number): number | undefined => {
			if (x >= -2 && x < this.numCols + 2 && y >= 0 && y < this.numRows) {
				return x + 2 + y * (this.numCols + 4)
			}
			return undefined
		}

		// Find edge tiles (walls not completely surrounded by other walls)
		let i = 0
		for (let y = 0; y < this.numRows; y++) {
			for (let x = -2; x < this.numCols + 2; x++, i++) {
				if (
					this.getTile(x, y) === '|' &&
					(this.getTile(x - 1, y) !== '|' ||
						this.getTile(x + 1, y) !== '|' ||
						this.getTile(x, y - 1) !== '|' ||
						this.getTile(x, y + 1) !== '|' ||
						this.getTile(x - 1, y - 1) !== '|' ||
						this.getTile(x - 1, y + 1) !== '|' ||
						this.getTile(x + 1, y - 1) !== '|' ||
						this.getTile(x + 1, y + 1) !== '|')
				) {
					edges[i] = true
				}
			}
		}

		const makePath = (tx: number, ty: number): void => {
			const dir = { x: 0, y: 0 }
			let dirEnum: Direction

			const rightIdx = toIndex(tx + 1, ty)
			const downIdx = toIndex(tx, ty + 1)

			if (rightIdx !== undefined && edges[rightIdx]) {
				dirEnum = Direction.RIGHT
			} else if (downIdx !== undefined && edges[downIdx]) {
				dirEnum = Direction.DOWN
			} else {
				return // Shouldn't be 1x1
			}
			setDirFromEnum(dir, dirEnum)

			tx += dir.x
			ty += dir.y

			const init_tx = tx
			const init_ty = ty
			const init_dirEnum = dirEnum

			const path: PathPoint[] = []
			let pad = 0
			let turn = false
			let turnAround = false

			const getStartPoint = (
				tx: number,
				ty: number,
				de: Direction
			): PathPoint => {
				const d = { x: 0, y: 0 }
				setDirFromEnum(d, de)

				const edgeIdx = toIndex(tx + d.y, ty - d.x)
				if (edgeIdx === undefined || !edges[edgeIdx]) {
					pad = this.isFloorTile(tx + d.y, ty - d.x) ? 5 : 0
				}

				let px = -TILE_SIZE / 2 + pad
				const py = TILE_SIZE / 2
				const a = getClockwiseAngleFromTop(de)
				const c = Math.cos(a)
				const s = Math.sin(a)

				return {
					x: px * c - py * s + (tx + 0.5) * TILE_SIZE,
					y: px * s + py * c + (ty + 0.5) * TILE_SIZE,
				}
			}

			// eslint-disable-next-line no-constant-condition
			while (true) {
				const idx = toIndex(tx, ty)
				if (idx !== undefined) {
					visited[idx] = true
				}

				const point = getStartPoint(tx, ty, dirEnum)

				if (turn && path.length > 0) {
					const lastPoint = path[path.length - 1]
					if (dir.x === 0) {
						point.cx = point.x
						point.cy = lastPoint.y
					} else {
						point.cx = lastPoint.x
						point.cy = point.y
					}
				}

				turn = false
				turnAround = false

				const leftIdx = toIndex(tx + dir.y, ty - dir.x)
				const straightIdx = toIndex(tx + dir.x, ty + dir.y)
				const rightIdx = toIndex(tx - dir.y, ty + dir.x)

				if (leftIdx !== undefined && edges[leftIdx]) {
					dirEnum = rotateLeft(dirEnum)
					turn = true
				} else if (straightIdx !== undefined && edges[straightIdx]) {
					// Continue straight
				} else if (rightIdx !== undefined && edges[rightIdx]) {
					dirEnum = rotateRight(dirEnum)
					turn = true
				} else {
					dirEnum = rotateAboutFace(dirEnum)
					turnAround = true
				}
				setDirFromEnum(dir, dirEnum)

				path.push(point)

				if (turnAround) {
					path.push(
						getStartPoint(tx - dir.x, ty - dir.y, rotateAboutFace(dirEnum))
					)
					path.push(getStartPoint(tx, ty, dirEnum))
				}

				tx += dir.x
				ty += dir.y

				if (tx === init_tx && ty === init_ty && dirEnum === init_dirEnum) {
					this.paths.push(path)
					break
				}
			}
		}

		// Build paths from all unvisited edge tiles
		i = 0
		for (let y = 0; y < this.numRows; y++) {
			for (let x = -2; x < this.numCols + 2; x++, i++) {
				if (edges[i] && !visited[i]) {
					visited[i] = true
					makePath(x, y)
				}
			}
		}
	}
}
