import { useCallback, useEffect, useState } from 'react';
import { useCarGame } from './hooks/useCarGame';
import { HUD } from './components/HUD';
import { BillboardStats } from './components/BillboardStats';
import { GameCanvas } from '../ui/GameCanvas';
import { GameOverlay } from '../ui/GameOverlay';
import { GameControls } from '../ui/GameControls';
import { isMobile } from '../../../../utils/functions';

interface RacingGameProps {
  lang?: string;
  laps: number;
  setPointsEarned: (points: number) => void;
  setGameOver: (isOver: boolean) => void;
  /**
   * Track layout to use:
   * 0 (default) - Original balanced track with variety
   * 1 - Speed Circuit: Fast track with long straights
   * 2 - Mountain Pass: Challenging hills and curves
   * 3 - Technical Circuit: Lots of curves and turns
   */
  track?: number;
  skin?: string;
  gameTitle?: string;
  brandColor?: string;
  brandLogo?: string;
  showBillboardStats?: boolean;
  maxPoints?: number;
}

const RacingGame = ({
  laps,
  setPointsEarned,
  setGameOver,
  track = 0,
  skin = 'default',
  gameTitle = 'JALO Racing',
  brandColor = '#00d26a',
  brandLogo,
  showBillboardStats = false,
  maxPoints,
}: RacingGameProps) => {
  const mobile = isMobile();
  const availableLaps = laps || 3;
  const [gameStarted, setGameStarted] = useState(false);

  // Use the new custom hook for game logic
  const {
    canvasRef,
    gameState,
    currentLap,
    points,
    hud,
    startGame,
    togglePause,
    setupTouchControls,
    handleTouchControl,
    getBillboardStats,
  } = useCarGame(availableLaps, track, skin, setPointsEarned, setGameOver, maxPoints);

  // Start game when instructions are dismissed
  const handleGameStart = async () => {
    setGameStarted(true);
    await startGame();
  };

  // Initialize canvas on mount
  useEffect(() => {
    if (canvasRef.current) {
      // Set initial canvas dimensions
      canvasRef.current.width = 720;
      canvasRef.current.height = 960;
    }
  }, [canvasRef]);

  // Setup touch controls when game starts on mobile
  useEffect(() => {
    if (mobile && gameState === 'playing') {
      setupTouchControls(true);
    }
  }, [mobile, gameState, setupTouchControls]);

  // Handle control input from GameControls
  const handleControl = useCallback(
    (direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2') => {
      if (gameState !== 'playing') return;

      // Directly update the input state through the hook
      handleTouchControl(direction, true);
    },
    [gameState, handleTouchControl]
  );

  const handleControlEnd = useCallback(
    (direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2') => {
      // Directly update the input state through the hook
      handleTouchControl(direction, false);
    },
    [handleTouchControl]
  );

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Prevent arrow key scrolling
      const keys: { [key: number]: number } = { 37: 1, 38: 1, 39: 1, 40: 1 };
      if (keys[e.keyCode]) {
        e.preventDefault();
        return false;
      }

      // Handle pause (ESC or Space)
      if (gameStarted && (e.key === 'Escape' || e.key === ' ')) {
        e.preventDefault();
        togglePause();
      }
    };

    window.addEventListener('keydown', handleKeyDown, false);
    return () => {
      window.removeEventListener('keydown', handleKeyDown, false);
    };
  }, [gameStarted, togglePause]);

  return (
    <div className="game-racing-wrapper">
      <div className="game-racing-main" style={{ backgroundColor: brandColor }}>
        {/* Instructions Overlay */}
        {!gameStarted && (
          <GameOverlay
            type="custom"
            title={gameTitle}
            brandColor={brandColor}
            onAction={handleGameStart}
            actionText="¡Empezar a Correr!"
            customContent={
              <div className="game-start-content-lg" style={{ marginBottom: '1rem' }}>
                {brandLogo && (
                  <>
                    <span className="game-brand-label">por:</span>
                    <img src={brandLogo} alt="Brand Logo" className="game-brand-logo" />
                  </>
                )}
                <p style={{ fontSize: '0.875rem', color: '#000000' }}>
                  {mobile
                    ? '¡Usa los controles táctiles para correr!'
                    : '¡Usa el teclado para correr!'}
                </p>

                <div className="game-racing-instructions">
                  {mobile ? (
                    <>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd-lg">←</kbd>
                        <span className="game-racing-instruction-text">Girar a la izquierda</span>
                      </div>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd-lg">→</kbd>
                        <span className="game-racing-instruction-text">Girar a la derecha</span>
                      </div>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd-lg game-racing-kbd-green">🏁</kbd>
                        <span className="game-racing-instruction-text">Acelerar</span>
                      </div>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd-lg game-racing-kbd-red">🛑</kbd>
                        <span className="game-racing-instruction-text">Frenar</span>
                      </div>
                    </>
                  ) : (
                    <>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd">←</kbd>
                        <span className="game-racing-instruction-text">o</span>
                        <kbd className="game-racing-kbd">A</kbd>
                        <span className="game-racing-instruction-text">- Girar a la izquierda</span>
                      </div>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd">→</kbd>
                        <span className="game-racing-instruction-text">o</span>
                        <kbd className="game-racing-kbd">D</kbd>
                        <span className="game-racing-instruction-text">- Girar a la derecha</span>
                      </div>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd">↑</kbd>
                        <span className="game-racing-instruction-text">o</span>
                        <kbd className="game-racing-kbd">W</kbd>
                        <span className="game-racing-instruction-text">- Acelerar</span>
                      </div>
                      <div className="game-racing-instruction-row">
                        <kbd className="game-racing-kbd">↓</kbd>
                        <span className="game-racing-instruction-text">o</span>
                        <kbd className="game-racing-kbd">S</kbd>
                        <span className="game-racing-instruction-text">- Frenar</span>
                      </div>
                    </>
                  )}
                </div>

                <p style={{ fontSize: '0.75rem', color: '#000000' }}>
                  ¡Recolecta monedas y evita chocar con otros autos!
                </p>
              </div>
            }
          />
        )}

        {/* Pause Overlay */}
        {gameState === 'paused' && (
          <GameOverlay
            type="pause"
            title="⏸️ PAUSA"
            message="Presiona ESC para continuar"
            onAction={togglePause}
            actionText="Continuar"
            brandColor={brandColor}
          />
        )}

        {/* Game Area */}
        <div id="racer" className="game-racing-racer">
          {gameState === 'gameover' && (
            <GameOverlay type="gameOver" score={points} brandColor={brandColor} />
          )}

          {/* Game Canvas Container - always present but hidden during ready state */}
          <div
            className="game-racing-canvas-area"
            style={{
              display: gameState === 'gameover' ? 'none' : 'block',
              visibility: gameState === 'ready' ? 'hidden' : 'visible',
            }}
          >
            {/* HUD Component */}
            <HUD
              currentLap={currentLap}
              availableLaps={availableLaps}
              points={points}
              hud={hud}
              gameState={gameState}
            />

            {/* Game Canvas */}
            <GameCanvas
              ref={canvasRef}
              width={720}
              height={960}
              className="game-full-width"
              style={{ backgroundColor: '#35cafa', width: '100%', height: '100%' }}
            />
          </div>
        </div>

        {/* Billboard Statistics (Debug Mode) */}
        <BillboardStats
          getBillboardStats={getBillboardStats}
          isVisible={showBillboardStats && gameState === 'playing' && !mobile}
        />

        {/* Game Controls */}
        {mobile && gameState === 'playing' && (
          <GameControls
            onControl={handleControl}
            onControlEnd={handleControlEnd}
            layout="racing"
            brandColor={brandColor}
            actionIcon="🏁"
            action2Icon="🛑"
          />
        )}
      </div>
    </div>
  );
};

export default RacingGame;
