import { useState, useRef, useCallback, useEffect } from 'react'
import type {
	Car,
	InputState,
	HudState,
	GameConfig,
	CoinAnimation,
	CrashAnimation,
} from '../types'
import { RoadEngine } from '../engine/road'
import { PhysicsEngine } from '../engine/physics'
import { RenderEngine } from '../engine/render'
import { GameLoop, ImageLoader, InputManager } from '../engine/gameLoop'
import { MathUtils } from '../utils/math'
import { DEFAULT_CONFIG, KEY, BACKGROUND } from '../constants'
import { isMobile } from '../../../../../utils/functions'
import { racingAudio } from '../utils/audioManager'
import { hapticManager } from '../../utils/hapticManager'

/**
 * Custom hook for managing 3D car game state and logic
 */
export function useCarGame(
	laps: number,
	track: number,
	skin: string,
	setPointsEarned: (points: number) => void,
	setGameOver: (isOver: boolean) => void,
	maxPoints?: number
) {
	const mobile = isMobile()

	// Game state
	const [gameState, setGameState] = useState<
		'loading' | 'ready' | 'playing' | 'paused' | 'gameover'
	>('loading')
	const gameStateRef = useRef(gameState)
	const [currentLap, setCurrentLap] = useState(1)
	const [points, setPoints] = useState(0)
	const pointsRef = useRef(0)
	const [hud, setHud] = useState<HudState>({
		speed: '0',
		current_lap_time: '00:00:0',
	})
	const coinAnimationsRef = useRef<CoinAnimation[]>([])
	const crashAnimationsRef = useRef<CrashAnimation[]>([])

	// Keep gameStateRef in sync
	useEffect(() => {
		gameStateRef.current = gameState
	}, [gameState])

	// Refs for game engines and state
	const canvasRef = useRef<HTMLCanvasElement>(null)
	const roadEngineRef = useRef<RoadEngine>(null)
	const physicsEngineRef = useRef<PhysicsEngine>(null)
	const renderEngineRef = useRef<RenderEngine>(null)
	const gameLoopRef = useRef<GameLoop>(null)
	const inputManagerRef = useRef<InputManager>(null)

	// Game world state
	const gameWorldRef = useRef({
		position: 0,
		speed: 0,
		playerX: 0,
		playerZ: 0,
		currentLapTime: 0,
		cars: [] as Car[],
		skyOffset: 0,
		hillOffset: 0,
		treeOffset: 0,
		background: null as HTMLImageElement | null,
		sprites: null as HTMLImageElement | null,
		hasRendered: false,
	})

	// Input state
	const inputStateRef = useRef<InputState>({
		left: false,
		right: false,
		faster: false,
		slower: false,
	})

	// Game configuration
	const configRef = useRef<GameConfig>({
		...DEFAULT_CONFIG,
		cameraDepth:
			1 / Math.tan(((DEFAULT_CONFIG.fieldOfView / 2) * Math.PI) / 180),
		maxSpeed: DEFAULT_CONFIG.segmentLength / ((1 / DEFAULT_CONFIG.fps) * 1.2),
		accel: 0, // Will be calculated
		breaking: 0, // Will be calculated
		decel: 0, // Will be calculated
		offRoadDecel: 0, // Will be calculated
		offRoadLimit: 0, // Will be calculated
		playerZ: 0, // Will be calculated in useEffect
	})

	// Calculate derived config values
	useEffect(() => {
		const config = configRef.current
		config.playerZ = config.cameraHeight * config.cameraDepth
		config.maxSpeed = config.segmentLength / ((1 / config.fps) * 1.2)
		config.accel = config.maxSpeed / 5
		config.breaking = -config.maxSpeed
		config.decel = -config.maxSpeed / 5
		config.offRoadDecel = -config.maxSpeed / 2
		config.offRoadLimit = config.maxSpeed / 4
	}, [])

	/**
	 * Format time for display
	 */
	const formatTime = useCallback((dt: number): string => {
		const minutes = Math.floor(dt / 60)
		const seconds = Math.floor(dt - minutes * 60)
		const tenths = Math.floor(10 * (dt - Math.floor(dt)))

		if (minutes > 0 && minutes < 10) {
			return `0${minutes}:${seconds < 10 ? '0' : ''}${seconds}:${tenths}`
		}
		if (minutes > 0 && minutes >= 10) {
			return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}:${tenths}`
		}
		return `00:${seconds < 10 ? '0' : ''}${seconds}:${tenths < 10 ? '0' : ''}${tenths}`
	}, [])

	/**
	 * Update HUD values
	 */
	const updateHud = useCallback((key: keyof HudState, value: string) => {
		setHud(prevHud => {
			if (prevHud[key] !== value) {
				return { ...prevHud, [key]: value }
			}
			return prevHud
		})
	}, [])

	/**
	 * Initialize game engines
	 */
	const initializeEngines = useCallback(() => {
		const canvas = canvasRef.current
		if (!canvas) return

		// Set canvas dimensions
		const config = configRef.current
		canvas.width = config.width
		canvas.height = config.height

		const ctx = canvas.getContext('2d')
		if (!ctx) return

		// Initialize engines
		roadEngineRef.current = new RoadEngine(
			config.segmentLength,
			config.rumbleLength
		)
		physicsEngineRef.current = new PhysicsEngine({
			maxSpeed: config.maxSpeed,
			accel: config.accel,
			breaking: config.breaking,
			decel: config.decel,
			offRoadDecel: config.offRoadDecel,
			offRoadLimit: config.offRoadLimit,
			centrifugal: config.centrifugal,
			trackLength: 0, // Will be updated after road generation
		})
		renderEngineRef.current = new RenderEngine(ctx, config.width, config.height)
		renderEngineRef.current.setCameraDepth(config.cameraDepth)
		inputManagerRef.current = new InputManager()

		// Setup input handlers
		inputManagerRef.current.setKeyHandlers([
			{
				keys: [KEY.LEFT, KEY.A],
				mode: 'down',
				action: () => {
					inputStateRef.current.left = true
				},
			},
			{
				keys: [KEY.RIGHT, KEY.D],
				mode: 'down',
				action: () => {
					inputStateRef.current.right = true
				},
			},
			{
				keys: [KEY.UP, KEY.W],
				mode: 'down',
				action: () => {
					inputStateRef.current.faster = true
				},
			},
			{
				keys: [KEY.DOWN, KEY.S],
				mode: 'down',
				action: () => {
					inputStateRef.current.slower = true
				},
			},
			{
				keys: [KEY.LEFT, KEY.A],
				mode: 'up',
				action: () => {
					inputStateRef.current.left = false
				},
			},
			{
				keys: [KEY.RIGHT, KEY.D],
				mode: 'up',
				action: () => {
					inputStateRef.current.right = false
				},
			},
			{
				keys: [KEY.UP, KEY.W],
				mode: 'up',
				action: () => {
					inputStateRef.current.faster = false
				},
			},
			{
				keys: [KEY.DOWN, KEY.S],
				mode: 'up',
				action: () => {
					inputStateRef.current.slower = false
				},
			},
		])

		return true
	}, [])

	/**
	 * Load game assets
	 */
	const loadAssets = useCallback(async () => {
		try {
			const images = await ImageLoader.loadImages(
				['background', 'sprites'],
				'/games/racing/images',
				skin
			)

			gameWorldRef.current.background = images[0]
			gameWorldRef.current.sprites = images[1]

			return true
		} catch (error) {
			console.error('Failed to load game assets:', error)
			return false
		}
	}, [skin])

	/**
	 * Reset game world
	 */
	const resetGame = useCallback(() => {
		const config = configRef.current
		const world = gameWorldRef.current

		// Reset world state
		world.position = 0
		world.speed = 0
		world.playerX = 0
		world.currentLapTime = 0
		world.skyOffset = 0
		world.hillOffset = 0
		world.treeOffset = 0

		// Reset road and cars
		if (roadEngineRef.current && physicsEngineRef.current) {
			roadEngineRef.current.reset(track, config.playerZ)
			const trackLength = roadEngineRef.current.getTrackLength()
			physicsEngineRef.current.updateTrackLength(trackLength)
			world.cars = roadEngineRef.current.resetCars(
				config.totalCars,
				config.maxSpeed
			)
		}

		// Reset UI state
		setCurrentLap(1)
		setPoints(0)
		coinAnimationsRef.current = []
		crashAnimationsRef.current = []
		updateHud('speed', '0')
		updateHud('current_lap_time', '00:00:0')
	}, [track, updateHud])

	/**
	 * Game update loop
	 */
	const update = useCallback(
		(dt: number) => {
			if (gameStateRef.current !== 'playing') return

			const config = configRef.current
			const world = gameWorldRef.current
			const physics = physicsEngineRef.current
			const road = roadEngineRef.current

			if (!physics || !road) return

			const playerSegment = road.findSegment(world.position + config.playerZ)
			const startPosition = world.position

			// Update player physics
			const playerUpdate = physics.updatePlayer(
				world.playerX,
				world.speed,
				world.position,
				inputStateRef.current,
				playerSegment,
				dt,
				z => road.findSegment(z),
				config.width,
				config.height
			)

			world.playerX = playerUpdate.playerX
			world.speed = playerUpdate.speed
			world.position = MathUtils.increase(
				world.position,
				dt * world.speed,
				road.getTrackLength()
			)

			// Handle points and crashes
			if (playerUpdate.pointsEarned !== 0) {
				const newTotal = Math.max(
					pointsRef.current + playerUpdate.pointsEarned,
					0
				)
				pointsRef.current = newTotal
				setPoints(newTotal)

				if (maxPoints && newTotal >= maxPoints) {
					setPointsEarned(Math.min(newTotal, maxPoints))
					setGameOver(true)
					stopGame()
					return
				}
			}

			// Handle coin collection animation
			if (playerUpdate.coinCollected && playerUpdate.pointsEarned > 0) {
				coinAnimationsRef.current.push({
					x: playerUpdate.coinCollected!.x,
					y: playerUpdate.coinCollected!.y,
					points: playerUpdate.pointsEarned,
					startTime: Date.now(),
				})
				racingAudio.playCoinCollect()
				hapticManager.goodHit()
			}

			// Handle crash animation
			if (playerUpdate.crashPosition && playerUpdate.crashed) {
				crashAnimationsRef.current.push({
					x: playerUpdate.crashPosition!.x,
					y: playerUpdate.crashPosition!.y,
					startTime: Date.now(),
				})
				racingAudio.playCollision()
				hapticManager.miss()
			}

			// Update engine sound based on speed
			racingAudio.updateEngineSound(world.speed / config.maxSpeed)

			// Update cars
			physics.updateCars(
				world.cars,
				dt,
				playerSegment,
				world.playerX,
				world.speed,
				config.drawDistance,
				z => road.findSegment(z),
				road.getSegments()
			)

			// Update background scroll
			const scrollUpdate = physics.updateScrollOffsets(
				world.skyOffset,
				world.hillOffset,
				world.treeOffset,
				playerSegment,
				startPosition,
				world.position,
				config.segmentLength,
				config.skySpeed,
				config.hillSpeed,
				config.treeSpeed
			)

			world.skyOffset = scrollUpdate.skyOffset
			world.hillOffset = scrollUpdate.hillOffset
			world.treeOffset = scrollUpdate.treeOffset

			// Handle lap completion
			if (world.position > config.playerZ) {
				if (world.currentLapTime && startPosition < config.playerZ) {
					setCurrentLap(prev => prev + 1)
					road.removeAllCoins()
					world.currentLapTime = 0
					racingAudio.playLapComplete()
					hapticManager.comboMilestone()
				} else {
					world.currentLapTime += dt
				}
			}

			// Update HUD
			updateHud('speed', String(5 * Math.round(world.speed / 500)))
			updateHud('current_lap_time', formatTime(world.currentLapTime))
		},
		// eslint-disable-next-line react-hooks/exhaustive-deps
		[gameState, formatTime, updateHud]
	)

	/**
	 * Game render loop
	 */
	const render = useCallback(
		(_interpolation: number) => {
			if (gameStateRef.current !== 'playing') {
				return
			}

			const config = configRef.current
			const world = gameWorldRef.current
			const renderer = renderEngineRef.current
			const road = roadEngineRef.current

			if (!renderer || !road || !world.background || !world.sprites) return

			renderer.clear()

			const baseSegment = road.findSegment(world.position)
			const basePercent = MathUtils.percentRemaining(
				world.position,
				config.segmentLength
			)
			const playerSegment = road.findSegment(world.position + config.playerZ)
			const playerPercent = MathUtils.percentRemaining(
				world.position + config.playerZ,
				config.segmentLength
			)
			const playerY = MathUtils.interpolate(
				playerSegment.p1.world.y,
				playerSegment.p2.world.y,
				playerPercent
			)

			let x = 0
			let dx = -(baseSegment.curve * basePercent)
			let maxy = config.height

			// Render background layers
			renderer.background(
				world.background,
				BACKGROUND.SKY,
				world.skyOffset,
				renderer.resolution * config.skySpeed * playerY
			)
			renderer.background(
				world.background,
				BACKGROUND.HILLS,
				world.hillOffset,
				renderer.resolution * config.hillSpeed * playerY
			)
			renderer.background(
				world.background,
				BACKGROUND.TREES,
				world.treeOffset,
				renderer.resolution * config.treeSpeed * playerY
			)

			// Render road segments
			const segments = road.getSegments()
			for (let n = 0; n < config.drawDistance; n++) {
				const segment = segments[(baseSegment.index + n) % segments.length]
				segment.looped = segment.index < baseSegment.index
				segment.fog = MathUtils.exponentialFog(
					n / config.drawDistance,
					config.fogDensity
				)
				segment.clip = maxy

				MathUtils.project(
					segment.p1,
					world.playerX * config.roadWidth - x,
					playerY + config.cameraHeight,
					world.position - (segment.looped ? road.getTrackLength() : 0),
					config.cameraDepth,
					config.width,
					config.height,
					config.roadWidth
				)
				MathUtils.project(
					segment.p2,
					world.playerX * config.roadWidth - x - dx,
					playerY + config.cameraHeight,
					world.position - (segment.looped ? road.getTrackLength() : 0),
					config.cameraDepth,
					config.width,
					config.height,
					config.roadWidth
				)

				x = x + dx
				dx = dx + segment.curve

				if (
					segment.p1.camera.z <= config.cameraDepth ||
					segment.p2.screen.y >= segment.p1.screen.y ||
					segment.p2.screen.y >= maxy
				) {
					continue
				}

				renderer.segment(
					config.lanes,
					segment.p1.screen.x,
					segment.p1.screen.y,
					segment.p1.screen.w,
					segment.p2.screen.x,
					segment.p2.screen.y,
					segment.p2.screen.w,
					segment.fog,
					segment.color
				)

				maxy = segment.p1.screen.y
			}

			// Render all objects in correct z-order
			renderer.renderObjects(
				segments,
				baseSegment.index,
				config.drawDistance,
				config.roadWidth,
				world.sprites,
				(sprite, segmentIndex, offset) => {
					// Track billboard impressions
					if (road.getBillboardName) {
						const billboardName = road.getBillboardName(sprite)
						if (billboardName) {
							road.recordBillboardImpression(
								segmentIndex,
								offset,
								billboardName,
								currentLap
							)
						}
					}
				}
			)

			// Render player
			renderer.player(
				config.roadWidth,
				world.sprites,
				world.speed / config.maxSpeed,
				config.cameraDepth / config.playerZ,
				config.width / 2,
				config.height / 2 -
					((config.cameraDepth / config.playerZ) *
						MathUtils.interpolate(
							playerSegment.p1.camera.y,
							playerSegment.p2.camera.y,
							playerPercent
						) *
						config.height) /
						2,
				world.speed *
					(inputStateRef.current.left
						? -1
						: inputStateRef.current.right
							? 1
							: 0),
				playerSegment.p2.world.y - playerSegment.p1.world.y
			)

			// Render coin animations
			const currentTime = Date.now()
			renderer.renderCoinAnimations(coinAnimationsRef.current, currentTime)
			renderer.renderCrashAnimations(crashAnimationsRef.current, currentTime)

			// Clean up expired animations
			coinAnimationsRef.current = coinAnimationsRef.current.filter(
				anim => currentTime - anim.startTime < 500
			)
			crashAnimationsRef.current = crashAnimationsRef.current.filter(
				anim => currentTime - anim.startTime < 500
			)
		},
		// eslint-disable-next-line react-hooks/exhaustive-deps
		[gameState]
	)

	/**
	 * Start the game
	 */
	const startGame = useCallback(async () => {
		setGameState('loading')

		if (!initializeEngines()) {
			console.error('Failed to initialize game engines')
			return
		}

		const assetsLoaded = await loadAssets()
		if (!assetsLoaded) {
			console.error('Failed to load game assets')
			return
		}

		resetGame()

		// Initialize audio, haptics and start engine
		await racingAudio.init()
		hapticManager.init()
		racingAudio.startEngine()

		// Initialize game loop
		gameLoopRef.current = new GameLoop(update, render, DEFAULT_CONFIG.fps)
		gameLoopRef.current.start()

		setGameState('playing')
	}, [initializeEngines, loadAssets, resetGame, update, render])

	/**
	 * Pause/unpause game
	 */
	const togglePause = useCallback(() => {
		if (gameState === 'playing') {
			setGameState('paused')
			gameLoopRef.current?.stop()
		} else if (gameState === 'paused') {
			setGameState('playing')
			gameLoopRef.current?.start()
		}
	}, [gameState])

	/**
	 * Stop the game
	 */
	const stopGame = useCallback(() => {
		gameLoopRef.current?.stop()
		inputManagerRef.current?.destroy()
		racingAudio.stopEngine()
		setGameState('gameover')
	}, [])

	// Check for game over condition
	useEffect(() => {
		if (currentLap > laps) {
			setPointsEarned(points)
			setGameOver(true)
			stopGame()
		}
	}, [currentLap, laps, points, setPointsEarned, setGameOver, stopGame])

	/**
	 * Setup touch controls for mobile
	 */
	const setupTouchControls = useCallback((isMobile: boolean) => {
		if (inputManagerRef.current) {
			inputManagerRef.current.setupTouchControls(isMobile)
		}
	}, [])

	// Setup touch controls after initialization
	useEffect(() => {
		if (gameState === 'playing' && inputManagerRef.current) {
			inputManagerRef.current.setupTouchControls(mobile)
		}
	}, [gameState, mobile])

	// Cleanup on unmount
	useEffect(() => {
		return () => {
			gameLoopRef.current?.stop()
			inputManagerRef.current?.destroy()
			racingAudio.dispose()
		}
	}, [])

	/**
	 * Handle touch control input directly
	 */
	const handleTouchControl = useCallback(
		(
			direction: 'up' | 'down' | 'left' | 'right' | 'action' | 'action2',
			isPressed: boolean
		) => {
			switch (direction) {
				case 'left':
					inputStateRef.current.left = isPressed
					break
				case 'right':
					inputStateRef.current.right = isPressed
					break
				case 'up':
					inputStateRef.current.faster = isPressed
					break
				case 'down':
					inputStateRef.current.slower = isPressed
					break
			}
		},
		[]
	)

	/**
	 * Get billboard statistics
	 */
	const getBillboardStats = useCallback(() => {
		if (roadEngineRef.current) {
			return roadEngineRef.current.getBillboardStats(laps)
		}
		return null
	}, [laps])

	return {
		canvasRef,
		gameState,
		currentLap,
		points,
		hud,
		availableLaps: laps,
		startGame,
		togglePause,
		stopGame,
		setupTouchControls,
		handleTouchControl,
		getBillboardStats,
	}
}
