import { useCallback, useEffect, useRef, useState } from 'react';
import maw_face from '../../../images/maw/maw_talking.gif';
import { GameCard } from './ui/GameCard';
import { GameOverlay } from './ui/GameOverlay';
import RacingGame from './racing/game';
import TetrisGame from './tetris/game';
import SnakeGame from './snake/index';
import FlappyBirdGame from './flappy-bird/index';
import BreakoutGame from './breakout/game';
import PenaltyShootoutGame from './penalty-shootout/index';
import CandyCrushGame from './candy-crush/index';
import RhythmHighway from './rhythm-highway/index';
import PacManGame from './pac-man/index';
import SoccerJugglingGame from './soccer-juggling/index';
import PageNavigation from '../PageNavigation/PageNavigation';
import { Language } from '../../../types/i18n';
import { getTranslations, interpolate } from '../../../i18n';

interface GameSelectorProps {
  visitor: string;
  setDialogText: (text: string) => void;
  setCurrentAction: (action: string) => void;
  lang: Language;
}

export default function GameSelector({ visitor, setDialogText, setCurrentAction, lang }: GameSelectorProps) {
  const t = getTranslations(lang);
  const [selectedGame, setSelectedGame] = useState('');
  const [showSplash, setShowSplash] = useState(false);
  const [splashExiting, setSplashExiting] = useState(false);
  const [pointsEarned, setPointsEarned] = useState<number>(0);
  const [gameOver, setGameOver] = useState<boolean>(false);

  const gameRef = useRef<any>(null);
  const splashTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const dismissSplash = useCallback(() => {
    if (!showSplash || splashExiting) return;
    setSplashExiting(true);
    if (splashTimerRef.current) {
      clearTimeout(splashTimerRef.current);
      splashTimerRef.current = null;
    }
    setTimeout(() => {
      setShowSplash(false);
      setSplashExiting(false);
    }, 400);
  }, [showSplash, splashExiting]);

  useEffect(() => {
    if (showSplash && !splashExiting) {
      splashTimerRef.current = setTimeout(dismissSplash, 2500);
      return () => {
        if (splashTimerRef.current) {
          clearTimeout(splashTimerRef.current);
          splashTimerRef.current = null;
        }
      };
    }
  }, [showSplash, splashExiting, dismissSplash]);

  const selectGame = (game: string) => {
    setSelectedGame(game);
    setShowSplash(true);
    setSplashExiting(false);
  };

  if (gameOver) {
    return (
      <div className="retro-page">
        <PageNavigation currentSection="goTo-games" onNavigate={setCurrentAction} lang={lang} />
        <div className="page-content">
          <GameOverlay
            type="custom"
            title={pointsEarned > 0 ? `🎉 ${t.games.congratulations}` : `😢 ${t.games.sorry}`}
            message={pointsEarned > 0 ? interpolate(t.games.wonPoints, { points: pointsEarned }) : t.games.tryAgain}
            brandColor="#00d26a"
            onAction={() => {
              setGameOver(false);
              setPointsEarned(0);
              setSelectedGame('');
            }}
            actionText={t.games.backToMenu}
            lang={lang}
          />
        </div>
      </div>
    );
  }

  if (selectedGame !== '') {
    return (
      <div className="retro-page">
        <PageNavigation currentSection="goTo-games" onNavigate={setCurrentAction} lang={lang} />
        <div className="page-content game-page-content">
          <button
            className="game-back-btn"
            onClick={() => { setSelectedGame(''); setShowSplash(false); setSplashExiting(false); }}
          >
            ← {t.games.backToMenu}
          </button>
          {showSplash ? (
            <div
              className={`game-splash${splashExiting ? ' game-splash-exit' : ''}`}
              onClick={dismissSplash}
            >
              <div className="game-splash-content">
                <div className="game-splash-avatar"><img src={maw_face} alt="MAW" /></div>
                <h1 className="game-splash-title">MAW GAMES</h1>
                <div className="game-splash-bar" />
              </div>
              <p className="game-splash-skip">tap to skip</p>
            </div>
          ) : (
          <div className="game-wrapper" ref={gameRef}>
            {selectedGame === 'races' && (
              <RacingGame
                laps={1}
                track={1}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                showBillboardStats={false}
                brandColor="#ef4444"
                gameTitle="MAW Racing"
                lang={lang}
              />
            )}
            {selectedGame === 'tetris' && (
              <TetrisGame
                lives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#8b5cf6"
                gameTitle={t.games.tetris.title}
              />
            )}
            {selectedGame === 'snake' && (
              <SnakeGame
                initialLives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#10b981"
                gameTitle={t.games.snake.title}
              />
            )}
            {selectedGame === 'flappy-bird' && (
              <FlappyBirdGame
                initialLives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#00bfff"
                gameTitle={t.games.flappyBird.title}
              />
            )}
            {selectedGame === 'breakout' && (
              <BreakoutGame
                lives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#f59e0b"
                gameTitle={t.games.breakout.title}
              />
            )}
            {selectedGame === 'penalty-shootout' && (
              <PenaltyShootoutGame
                lives={5}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#1a472a"
                gameTitle={t.games.penaltyShootout.title}
              />
            )}
            {selectedGame === 'candy-crush' && (
              <CandyCrushGame
                lives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#e91e63"
                gameTitle={t.games.candyCrush.title}
              />
            )}
            {selectedGame === 'rhythm-highway' && (
              <RhythmHighway
                initialLives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#6366f1"
                gameTitle={t.games.rhythmHighway.title}
              />
            )}
            {selectedGame === 'pac-man' && (
              <PacManGame
                lives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#2121ff"
                gameTitle={t.games.pacMan.title}
              />
            )}
            {selectedGame === 'soccer-juggling' && (
              <SoccerJugglingGame
                lives={3}
                setGameOver={setGameOver}
                setPointsEarned={setPointsEarned}
                brandColor="#2d8a4e"
                gameTitle={t.games.soccerJuggling.title}
              />
            )}
          </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="retro-page">
      <PageNavigation currentSection="goTo-games" onNavigate={setCurrentAction} lang={lang} />
      <div className="page-content">
        <h1>{t.games.title}</h1>

        <div className="retro-box" style={{ textAlign: 'center', marginBottom: '20px' }}>
          {t.games.subtitle}
        </div>

        <div className="game-selector-container">
          <div className="game-selector-grid">
            <GameCard
              title={t.games.racing.title}
              icon="🏎️"
              gradientFrom="#3b82f6"
              gradientTo="#2563eb"
              onClick={() => selectGame('races')}
              description={t.games.racing.description}
            />
            <GameCard
              title={t.games.tetris.title}
              icon="🧱"
              gradientFrom="#8b5cf6"
              gradientTo="#7c3aed"
              onClick={() => selectGame('tetris')}
              description={t.games.tetris.description}
            />
            <GameCard
              title={t.games.snake.title}
              icon="🐍"
              gradientFrom="#10b981"
              gradientTo="#059669"
              onClick={() => selectGame('snake')}
              description={t.games.snake.description}
            />
            <GameCard
              title={t.games.flappyBird.title}
              icon="🐦"
              gradientFrom="#00bfff"
              gradientTo="#0099cc"
              onClick={() => selectGame('flappy-bird')}
              description={t.games.flappyBird.description}
            />
            <GameCard
              title={t.games.breakout.title}
              icon="🧱"
              gradientFrom="#f59e0b"
              gradientTo="#d97706"
              onClick={() => selectGame('breakout')}
              description={t.games.breakout.description}
            />
            <GameCard
              title={t.games.penaltyShootout.title}
              icon="⚽"
              gradientFrom="#1a472a"
              gradientTo="#0f2d1a"
              onClick={() => selectGame('penalty-shootout')}
              description={t.games.penaltyShootout.description}
            />
            <GameCard
              title={t.games.candyCrush.title}
              icon="🍬"
              gradientFrom="#e91e63"
              gradientTo="#c2185b"
              onClick={() => selectGame('candy-crush')}
              description={t.games.candyCrush.description}
            />
            <GameCard
              title={t.games.rhythmHighway.title}
              icon="🎵"
              gradientFrom="#6366f1"
              gradientTo="#4f46e5"
              onClick={() => selectGame('rhythm-highway')}
              description={t.games.rhythmHighway.description}
            />
            <GameCard
              title={t.games.pacMan.title}
              icon="👾"
              gradientFrom="#2121ff"
              gradientTo="#1a1acc"
              onClick={() => selectGame('pac-man')}
              description={t.games.pacMan.description}
            />
            <GameCard
              title={t.games.soccerJuggling.title}
              icon="⚽"
              gradientFrom="#2d8a4e"
              gradientTo="#1e6b3a"
              onClick={() => selectGame('soccer-juggling')}
              description={t.games.soccerJuggling.description}
            />
          </div>
        </div>
      </div>
    </div>
  );
}
