import React from 'react';

interface FavoritesDropdownProps {
  translations: {
    github: string;
    stackoverflow: string;
    mdn: string;
    hackernews: string;
    csstricks: string;
    devto: string;
  };
}

const favorites = [
  { key: 'github' as const, url: 'https://github.com' },
  { key: 'stackoverflow' as const, url: 'https://stackoverflow.com' },
  { key: 'mdn' as const, url: 'https://developer.mozilla.org' },
  { key: 'hackernews' as const, url: 'https://news.ycombinator.com' },
  { key: 'csstricks' as const, url: 'https://css-tricks.com' },
  { key: 'devto' as const, url: 'https://dev.to' },
];

const FavoritesDropdown: React.FC<FavoritesDropdownProps> = ({ translations }) => {
  return (
    <div className="theme-dropdown">
      {favorites.map(({ key, url }) => (
        <a
          key={key}
          href={url}
          target="_blank"
          rel="noreferrer"
          className="favorites-link"
        >
          {translations[key]}
        </a>
      ))}
    </div>
  );
};

export default FavoritesDropdown;
